      }
    ],
    "schedules": [
      {
        "cron": "0 * * * *",
        "function_name": "support-ticket.reindex.v1",
        "input": {},
        "name": "support-ticket-reindex"
      }
    ],
    "workflows": [
      {
        "inputContract": {
          "contractId": "support.ticket-triage-input",
          "version": "v1"
        },
        "name": "ticket_triage",
        "owner": "support-ticket",
        "protocol": "lenso.workflow-definition.v1",
        "resultContract": {
          "contractId": "support.ticket-triage-result",
          "version": "v1"
        },
        "steps": [
          {
            "name": "classify"
          }
        ],
        "version": "v1"
      }
    ]
  },
  "story_display": [
    {
      "display_name": "Reindex support tickets",
      "source": {
        "kind": "execution_name",
        "name": "support-ticket.reindex.v1"
      },
      "story_title": "Support ticket maintenance"
    }
